PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT (SUBSTR(str(?eventDate), 1, 4) AS ?year)
WHERE {
  ?event wdt:P31 wd:Q151554;
         wdt:P361 wd:Q2843578;
         wdt:P2085 wd:Q30.
  ?event wdt:P585 ?eventDate.
}
ORDER BY DESC(?eventDate)
LIMIT 1

